InMemoryRepository.cs
using System;
using System.Collections.Generic;
using System.Linq;
using HRManagement.Models;

namespace HRManagement.Repository
{
    public class InMemoryRepository
    {
        // expose read-only interfaces
        private readonly List<User> _users = new List<User>();
        private readonly List<Employee> _employees = new List<Employee>();

        public IReadOnlyList<User> Users => _users;
        public IReadOnlyList<Employee> Employees => _employees;

        public InMemoryRepository()
        {
            // sample users
            _users.Add(new User { Username = "admin", Password = "admin", Role = UserRole.Admin });
            _users.Add(new User { Username = "staff", Password = "staff", Role = UserRole.Staff });

            // sample employees
            _employees.Add(new Employee { EmployeeId = "E001", FullName = "Nguyen Van A", BirthDate = new DateTime(1990, 1, 1), Gender = "Nam", Department = "IT", Phone = "0123456789", Email = "a@example.com" });
            _employees.Add(new Employee { EmployeeId = "E002", FullName = "Tran Thi B", BirthDate = new DateTime(1992, 2, 2), Gender = "Nữ", Department = "HR", Phone = "0987654321", Email = "b@example.com" });
        }

        // Users
        public User ValidateUser(string username, string password)
        {
            return _users.FirstOrDefault(u => u.Username == username && u.Password == password);
        }

        public bool AddUser(User u)
        {
            if (_users.Any(x => x.Username == u.Username)) return false;
            _users.Add(u);
            return true;
        }

        public bool UpdateUser(User u)
        {
            var ex = _users.FirstOrDefault(x => x.Username == u.Username);
            if (ex == null) return false;
            ex.Password = u.Password;
            ex.Role = u.Role;
            return true;
        }

        public bool RemoveUser(string username)
        {
            var ex = _users.FirstOrDefault(x => x.Username == username);
            if (ex == null) return false;
            _users.Remove(ex);
            return true;
        }

        // Employees
        public bool AddEmployee(Employee e)
        {
            if (_employees.Any(x => x.EmployeeId == e.EmployeeId)) return false;
            _employees.Add(e);
            return true;
        }

        public bool UpdateEmployee(Employee e)
        {
            var ex = _employees.FirstOrDefault(x => x.EmployeeId == e.EmployeeId);
            if (ex == null) return false;
            ex.FullName = e.FullName;
            ex.BirthDate = e.BirthDate;
            ex.Gender = e.Gender;
            ex.Department = e.Department;
            ex.Phone = e.Phone;
            ex.Email = e.Email;
            return true;
        }

        public bool RemoveEmployee(string id)
        {
            var ex = _employees.FirstOrDefault(x => x.EmployeeId == id);
            if (ex == null) return false;
            _employees.Remove(ex);
            return true;
        }

        public IEnumerable<Employee> SearchEmployees(string name, string gender, DateTime? dob, string id)
        {
            var q = _employees.AsEnumerable();
            if (!string.IsNullOrWhiteSpace(name)) q = q.Where(x => x.FullName.IndexOf(name, StringComparison.OrdinalIgnoreCase) >= 0);
            if (!string.IsNullOrWhiteSpace(gender)) q = q.Where(x => x.Gender == gender);
            if (dob.HasValue) q = q.Where(x => x.BirthDate?.Date == dob.Value.Date);
            if (!string.IsNullOrWhiteSpace(id)) q = q.Where(x => x.EmployeeId.IndexOf(id, StringComparison.OrdinalIgnoreCase) >= 0);
            return q;
        }
    }
}




EmployeeDataAccess.cs
using System;
using System.Data;
using System.Data.SqlClient;

public class EmployeeDataAccess
{
    private readonly string _connString = "Data Source=.;Initial Catalog=HRManagement;Integrated Security=True;"; // điều chỉnh theo môi trường

    public void InsertEmployee(string id, string name, DateTime? birthDate, byte? genderId, int? deptId, string phone, string email, byte[] photo)
    {
        using (var cn = new SqlConnection(_connString))
        using (var cmd = new SqlCommand("dbo.usp_InsertEmployee", cn))
        {
            cmd.CommandType = CommandType.StoredProcedure;
            cmd.Parameters.AddWithValue("@EmployeeId", id);
            cmd.Parameters.AddWithValue("@FullName", name);
            cmd.Parameters.AddWithValue("@BirthDate", (object)birthDate ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@GenderId", (object)genderId ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@DepartmentId", (object)deptId ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@Phone", (object)phone ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@Email", (object)email ?? DBNull.Value);
            cmd.Parameters.Add("@Photo", SqlDbType.VarBinary, -1).Value = (object)photo ?? DBNull.Value;

            cn.Open();
            cmd.ExecuteNonQuery();
        }
    }

    public void UpdateEmployee(string id, string name, DateTime? birthDate, byte? genderId, int? deptId, string phone, string email, byte[] photo)
    {
        using (var cn = new SqlConnection(_connString))
        using (var cmd = new SqlCommand("dbo.usp_UpdateEmployee", cn))
        {
            cmd.CommandType = CommandType.StoredProcedure;
            cmd.Parameters.AddWithValue("@EmployeeId", id);
            cmd.Parameters.AddWithValue("@FullName", name);
            cmd.Parameters.AddWithValue("@BirthDate", (object)birthDate ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@GenderId", (object)genderId ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@DepartmentId", (object)deptId ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@Phone", (object)phone ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@Email", (object)email ?? DBNull.Value);
            cmd.Parameters.Add("@Photo", SqlDbType.VarBinary, -1).Value = (object)photo ?? DBNull.Value;

            cn.Open();
            cmd.ExecuteNonQuery();
        }
    }

    public DataTable SearchEmployees(string name, byte? genderId, DateTime? birthDate, string employeeId, int? departmentId)
    {
        var dt = new DataTable();
        using (var cn = new SqlConnection(_connString))
        using (var cmd = new SqlCommand("dbo.usp_SearchEmployees", cn))
        {
            cmd.CommandType = CommandType.StoredProcedure;
            cmd.Parameters.AddWithValue("@Name", (object)name ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@GenderId", (object)genderId ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@BirthDate", (object)birthDate ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@EmployeeId", (object)employeeId ?? DBNull.Value);
            cmd.Parameters.AddWithValue("@DepartmentId", (object)departmentId ?? DBNull.Value);

            using (var da = new SqlDataAdapter(cmd))
            {
                da.Fill(dt);
            }
        }
        return dt;
    }
}



