using System;
using System.Drawing;
using System.Windows.Forms;
using HRManagement.Models;
using HRManagement.Repository;

namespace HRManagement
{
    public partial class FormAddEmployee : Form
    {
        InMemoryRepository repo;
        Employee editEmployee;

        TextBox txtId, txtName, txtPhone, txtEmail;
        ComboBox cboGender, cboDept;
        DateTimePicker dtpDob;
        Button btnSave, btnCancel;

        public FormAddEmployee(InMemoryRepository repository, Employee employee = null)
        {
            repo = repository;
            editEmployee = employee;
            Text = employee == null ? "Thêm nhân viên" : "Sửa nhân viên";
            Size = new Size(420, 360);
            StartPosition = FormStartPosition.CenterParent;
            InitializeComponents();
            if (employee != null) LoadEmployee();
        }

        void InitializeComponents()
        {
            Label lId = new Label { Text = "Mã nhân viên", Location = new Point(20, 20), AutoSize = true };
            txtId = new TextBox { Location = new Point(140, 18), Width = 220 };

            Label lName = new Label { Text = "Họ tên", Location = new Point(20, 60), AutoSize = true };
            txtName = new TextBox { Location = new Point(140, 58), Width = 220 };

            Label lDob = new Label { Text = "Ngày sinh", Location = new Point(20, 100), AutoSize = true };
            dtpDob = new DateTimePicker { Location = new Point(140, 96), Width = 220, Format = DateTimePickerFormat.Short };

            Label lGender = new Label { Text = "Giới tính", Location = new Point(20, 140), AutoSize = true };
            cboGender = new ComboBox { Location = new Point(140, 136), Width = 120 };
            cboGender.Items.AddRange(new string[] { "Nam", "Nữ", "Khác" });

            Label lDept = new Label { Text = "Phòng ban", Location = new Point(20, 180), AutoSize = true };
            cboDept = new ComboBox { Location = new Point(140, 178), Width = 220 };
            cboDept.Items.AddRange(new string[] { "Kỹ thuật", "Kế toán", "Công nghệ", "QLCL", "Cơ điện", "Mạ Sơn", "Tẩy cán", "Kho" });

            Label lPhone = new Label { Text = "Điện thoại", Location = new Point(20, 220), AutoSize = true };
            txtPhone = new TextBox { Location = new Point(140, 218), Width = 220 };

            Label lEmail = new Label { Text = "Email", Location = new Point(20, 260), AutoSize = true };
            txtEmail = new TextBox { Location = new Point(140, 258), Width = 220 };

            btnSave = new Button { Text = "Lưu", Location = new Point(140, 295), Width = 80 };
            btnCancel = new Button { Text = "Hủy", Location = new Point(240, 295), Width = 80 };

            btnSave.Click += BtnSave_Click;
            btnCancel.Click += (s, e) => Close();

            Controls.AddRange(new Control[] { lId, txtId, lName, txtName, lDob, dtpDob, lGender, cboGender, lDept, cboDept, lPhone, txtPhone, lEmail, txtEmail, btnSave, btnCancel });
        }

        void LoadEmployee()
        {
            txtId.Text = editEmployee.EmployeeId;
            txtId.Enabled = false;
            txtName.Text = editEmployee.FullName;
            if (editEmployee.BirthDate.HasValue) dtpDob.Value = editEmployee.BirthDate.Value;
            cboGender.Text = editEmployee.Gender;
            cboDept.Text = editEmployee.Department;
            txtPhone.Text = editEmployee.Phone;
            txtEmail.Text = editEmployee.Email;
        }

        void BtnSave_Click(object sender, EventArgs e)
        {
            if (string.IsNullOrWhiteSpace(txtId.Text) || string.IsNullOrWhiteSpace(txtName.Text))
            {
                MessageBox.Show("Mã và họ tên bắt buộc.");
                return;
            }

            var emp = new Employee
            {
                EmployeeId = txtId.Text.Trim(),
                FullName = txtName.Text.Trim(),
                BirthDate = dtpDob.Value,
                Gender = cboGender.Text,
                Department = cboDept.Text.Trim(),
                Phone = txtPhone.Text.Trim(),
                Email = txtEmail.Text.Trim()
            };

            bool ok;
            if (editEmployee == null)
                ok = repo.AddEmployee(emp);
            else
                ok = repo.UpdateEmployee(emp);

            if (!ok) MessageBox.Show("Thao tác không thành công (mã đã tồn tại?).");
            else Close();
        }
    }
}


