using System;
using System.Drawing;
using System.Windows.Forms;
using HRManagement.Repository;

namespace HRManagement
{
    public partial class FormLogin : Form
    {
        private TextBox txtUser;
        private TextBox txtPass;
        private CheckBox chkShow;
        private Button btnLogin;
        private Button btnExit;
        private readonly InMemoryRepository repo;

        public FormLogin() : this(new InMemoryRepository()) { }

        // Allow repository injection for easier testing / future changes
        public FormLogin(InMemoryRepository repository)
        {
            repo = repository ?? throw new ArgumentNullException(nameof(repository));
            Text = "Đăng nhập";
            Size = new Size(420, 220);
            StartPosition = FormStartPosition.CenterScreen;

            // Designer file has InitializeComponent(); keep it intact.
            // Call custom UI initialization for programmatic controls.
            InitializeComponent();
            InitializeCustomComponents();
        }

        // Keep this private and clearly named to avoid colliding with designer-generated InitializeComponent
        private void InitializeCustomComponents()
        {
            Label lblUser = new Label { Text = "Tài khoản", Location = new Point(20, 20), AutoSize = true, Font = new Font("Tahoma", 12) };
            txtUser = new TextBox { Location = new Point(140, 20), Width = 220 };

            Label lblPass = new Label { Text = "Mật khẩu", Location = new Point(20, 60), AutoSize = true, Font = new Font("Tahoma", 12) };
            txtPass = new TextBox { Location = new Point(140, 60), Width = 220, UseSystemPasswordChar = true };

            chkShow = new CheckBox { Text = "Hiển thị mật khẩu", Location = new Point(140, 90), AutoSize = true };
            chkShow.CheckedChanged += (s, e) => txtPass.UseSystemPasswordChar = !chkShow.Checked;

            btnLogin = new Button { Text = "Đăng nhập", Location = new Point(140, 120), Width = 100 };
            btnExit = new Button { Text = "Thoát", Location = new Point(260, 120), Width = 100 };

            btnLogin.Click += BtnLogin_Click;
            btnExit.Click += (s, e) => Application.Exit();

            // Accept / Cancel
            AcceptButton = btnLogin;
            CancelButton = btnExit;

            Controls.AddRange(new Control[] { lblUser, txtUser, lblPass, txtPass, chkShow, btnLogin, btnExit });
        }

        private void BtnLogin_Click(object sender, EventArgs e)
        {
            var username = txtUser.Text?.Trim();
            var password = txtPass.Text ?? string.Empty;

            if (string.IsNullOrWhiteSpace(username))
            {
                MessageBox.Show("Vui lòng nhập tên đăng nhập.", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                txtUser.Focus();
                return;
            }

            // ValidateUser should handle password checks; keep call minimal
            var user = repo.ValidateUser(username, password);
            if (user != null)
            {
                var main = new FormMain(repo, user);
                Hide();
                main.FormClosed += (s, ev) => Close();
                main.Show();
            }
            else
            {
                MessageBox.Show("Sai tên đăng nhập hoặc mật khẩu", "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                txtPass.SelectAll();
                txtPass.Focus();
            }
        }
    }
}


