using HRManagement.Models;
using HRManagement.Repository;
using System;
using System.Drawing;
using System.Linq;
using System.Reflection;
using System.Windows.Forms;

namespace HRManagement
{
    public partial class FormMain : Form
    {
        InMemoryRepository repo;
        User currentUser;
        DataGridView dgv;
        TextBox txtName, txtId;
        ComboBox cboGender;
        DateTimePicker dtpDob;
        Label lblAdmin;

        public FormMain(InMemoryRepository repository, User loggedUser)
        {
            // Validate inputs early to fail fast and avoid null dereferences later
            repo = repository ?? throw new ArgumentNullException(nameof(repository));
            currentUser = loggedUser ?? throw new ArgumentNullException(nameof(loggedUser));

            Text = "Quản lý nhân sự - Công ty TNHH ABB";
            Size = new Size(900, 650);
            StartPosition = FormStartPosition.CenterScreen;
            InitializeComponents();
            LoadEmployees();
        }

        void InitializeComponents()
        {
            // Menu / Toolstrip (simplified)
            ToolStrip ts = new ToolStrip();
            var btnAdd = new ToolStripButton("Thêm");
            var btnEdit = new ToolStripButton("Sửa");
            var btnDel = new ToolStripButton("Xóa");
            var btnSave = new ToolStripButton("Lưu");
            var btnRefresh = new ToolStripButton("Cập nhật");
            ts.Items.AddRange(new ToolStripItem[] { btnAdd, btnEdit, btnDel, btnSave, btnRefresh });

            btnAdd.Click += (s, e) => {
                var f = new FormAddEmployee(repo);
                f.FormClosed += (ss, ee) => LoadEmployees();
                f.ShowDialog();
            };
            btnEdit.Click += (s, e) => EditSelected();
            btnDel.Click += (s, e) => DeleteSelected();

            Controls.Add(ts);

            GroupBox gbSearch = new GroupBox { Text = "Tìm kiếm", Location = new Point(10, 40), Size = new Size(860, 120) };
            Label lName = new Label { Text = "Họ Tên", Location = new Point(10, 25), AutoSize = true };
            txtName = new TextBox { Location = new Point(90, 22), Width = 250 };

            Label lGender = new Label { Text = "Giới tính", Location = new Point(360, 25), AutoSize = true };
            cboGender = new ComboBox { Location = new Point(430, 22), Width = 120 };
            cboGender.Items.AddRange(new string[] { "", "Nam", "Nữ", "Khác" });

            Label lDob = new Label { Text = "Ngày sinh", Location = new Point(10, 60), AutoSize = true };
            dtpDob = new DateTimePicker { Location = new Point(90, 56), Width = 200, Format = DateTimePickerFormat.Short, ShowCheckBox = true };

            Label lId = new Label { Text = "Mã nhân viên", Location = new Point(360, 60), AutoSize = true };
            txtId = new TextBox { Location = new Point(450, 56), Width = 150 };

            Button btnSearch = new Button { Text = "Tìm kiếm", Location = new Point(620, 45), Size = new Size(90, 40) };
            btnSearch.Click += (s, e) => LoadEmployees();

            gbSearch.Controls.AddRange(new Control[] { lName, txtName, lGender, cboGender, lDob, dtpDob, lId, txtId, btnSearch });
            Controls.Add(gbSearch);

            Label title = new Label { Text = "DANH SÁCH NHÂN VIÊN", Font = new Font("Times New Roman", 16, FontStyle.Bold), AutoSize = false, TextAlign = ContentAlignment.MiddleCenter, Location = new Point(10, 170), Size = new Size(860, 30) };
            Controls.Add(title);

            dgv = new DataGridView { Location = new Point(10, 210), Size = new Size(860, 360), ReadOnly = true, SelectionMode = DataGridViewSelectionMode.FullRowSelect, AutoGenerateColumns = false };
            dgv.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Mã", DataPropertyName = "EmployeeId", Width = 80 });
            dgv.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Họ Tên", DataPropertyName = "FullName", Width = 220 });
            dgv.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Ngày sinh", DataPropertyName = "BirthDate", Width = 100 });
            dgv.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Giới tính", DataPropertyName = "Gender", Width = 80 });
            dgv.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Phòng ban", DataPropertyName = "Department", Width = 140 });
            dgv.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Điện thoại", DataPropertyName = "Phone", Width = 120 });
            dgv.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Email", DataPropertyName = "Email", Width = 120 });

            Controls.Add(dgv);

            lblAdmin = new Label { Text = $"Admin: {currentUser?.Username ?? "Unknown"}", Location = new Point(10, 580), AutoSize = true };
            Controls.Add(lblAdmin);

            // Right-click menu to open Users form if admin (guarded)
            if (currentUser != null && currentUser.Role == UserRole.Admin)
            {
                var menu = new ContextMenuStrip();
                var miUsers = new ToolStripMenuItem("Quản lý Users");
                miUsers.Click += (s, e) => {
                    var fu = new FormUsers(repo);
                    fu.ShowDialog();
                };
                menu.Items.Add(miUsers);
                ContextMenuStrip = menu;
            }
        }

        void LoadEmployees()
        {
            DateTime? dob = dtpDob.Checked ? (DateTime?)dtpDob.Value.Date : null;
            var data = repo.SearchEmployees(txtName.Text.Trim(), cboGender.Text, dob, txtId.Text.Trim());
            dgv.DataSource = data.Select(x => new {
                x.EmployeeId,
                x.FullName,
                BirthDate = x.BirthDate?.ToString("dd/MM/yyyy"),
                x.Gender,
                x.Department,
                x.Phone,
                x.Email
            }).ToList();
        }

        void EditSelected()
        {
            if (dgv.SelectedRows.Count == 0) { MessageBox.Show("Chọn nhân viên để sửa."); return; }
            var id = dgv.SelectedRows[0].Cells[0].Value.ToString();
            var emp = repo.Employees.FirstOrDefault(x => x.EmployeeId == id);
            if (emp == null) return;
            var f = new FormAddEmployee(repo, emp);
            f.FormClosed += (s, e) => LoadEmployees();
            f.ShowDialog();
        }

        void DeleteSelected()
        {
            if (dgv.SelectedRows.Count == 0) { MessageBox.Show("Chọn nhân viên để xóa."); return; }
            var id = dgv.SelectedRows[0].Cells[0].Value.ToString();
            if (MessageBox.Show($"Xác nhận xóa nhân viên {id}?", "Xóa", MessageBoxButtons.YesNo) == DialogResult.Yes)
            {
                repo.RemoveEmployee(id);
                LoadEmployees();
            }
        }
    }
}

