using System;
using System.Drawing;
using System.Linq;
using System.Windows.Forms;
using HRManagement.Models;
using HRManagement.Repository;

namespace HRManagement
{
    // Mark class as partial because a designer partial exists (fixes CS0260).
    public partial class FormUsers : Form
    {
        InMemoryRepository repo;
        TextBox txtUser, txtPass;
        ComboBox cboRole;
        ListBox lstUsers;
        Button btnAdd, btnEdit, btnDelete, btnClose;

        public FormUsers(InMemoryRepository repository)
        {
            repo = repository ?? throw new ArgumentNullException(nameof(repository));
            Text = "FormUsers";
            Size = new Size(700, 420);
            StartPosition = FormStartPosition.CenterParent;
            InitializeComponents();
            LoadUsers();
        }

        void InitializeComponents()
        {
            Label lUser = new Label { Text = "Tên tài khoản", Location = new Point(20, 20), AutoSize = true };
            txtUser = new TextBox { Location = new Point(140, 18), Width = 200 };

            Label lPass = new Label { Text = "Mật khẩu", Location = new Point(20, 60), AutoSize = true };
            txtPass = new TextBox { Location = new Point(140, 58), Width = 200, UseSystemPasswordChar = true };

            Label lRole = new Label { Text = "Loại tài khoản", Location = new Point(20, 100), AutoSize = true };
            cboRole = new ComboBox { Location = new Point(140, 98), Width = 200, DropDownStyle = ComboBoxStyle.DropDownList };
            cboRole.Items.AddRange(new string[] { "Admin", "Staff" });
            cboRole.SelectedIndex = 0;

            btnAdd = new Button { Text = "Thêm", Location = new Point(20, 150) };
            btnEdit = new Button { Text = "Sửa", Location = new Point(110, 150) };
            btnDelete = new Button { Text = "Xóa", Location = new Point(200, 150) };
            btnClose = new Button { Text = "Thoát", Location = new Point(20, 330), DialogResult = DialogResult.Cancel };

            lstUsers = new ListBox { Location = new Point(360, 18), Size = new Size(300, 330) };

            btnAdd.Click += BtnAdd_Click;
            btnEdit.Click += BtnEdit_Click;
            btnDelete.Click += BtnDelete_Click;
            btnClose.Click += (s, e) => Close();
            lstUsers.SelectedIndexChanged += (s, e) =>
            {
                var u = lstUsers.SelectedItem as User;
                if (u != null)
                {
                    txtUser.Text = u.Username;
                    txtPass.Text = u.Password;
                    cboRole.SelectedItem = u.Role.ToString();
                    txtUser.Enabled = false;
                }
                else
                {
                    txtUser.Enabled = true;
                    txtUser.Text = txtPass.Text = "";
                    cboRole.SelectedIndex = 0;
                }
            };

            Controls.AddRange(new Control[] { lUser, txtUser, lPass, txtPass, lRole, cboRole, btnAdd, btnEdit, btnDelete, btnClose, lstUsers });

            // Optional form-level behavior
            AcceptButton = btnAdd;
            CancelButton = btnClose;
        }

        void LoadUsers()
        {
            // DisplayMember should be set before assigning DataSource to avoid flicker/late-binding issues.
            lstUsers.DataSource = null;
            lstUsers.DisplayMember = "Username";
            lstUsers.ValueMember = "Username";
            lstUsers.DataSource = repo.Users.ToList();
        }

        private void BtnAdd_Click(object sender, EventArgs e)
        {
            if (string.IsNullOrWhiteSpace(txtUser.Text) || string.IsNullOrWhiteSpace(txtPass.Text))
            {
                MessageBox.Show("User/pass required.");
                return;
            }

            if (!Enum.TryParse<UserRole>(cboRole.Text, true, out var role))
            {
                MessageBox.Show("Loại tài khoản không hợp lệ.");
                return;
            }

            var u = new User
            {
                Username = txtUser.Text.Trim(),
                Password = txtPass.Text,
                Role = role
            };

            if (!repo.AddUser(u))
            {
                MessageBox.Show("Tài khoản đã tồn tại.");
            }
            else
            {
                // Clear inputs after successful add
                txtUser.Text = txtPass.Text = "";
                cboRole.SelectedIndex = 0;
            }

            LoadUsers();
        }

        private void BtnEdit_Click(object sender, EventArgs e)
        {
            if (string.IsNullOrWhiteSpace(txtUser.Text)) return;

            if (!Enum.TryParse<UserRole>(cboRole.Text, true, out var role))
            {
                MessageBox.Show("Loại tài khoản không hợp lệ.");
                return;
            }

            var u = new User
            {
                Username = txtUser.Text.Trim(),
                Password = txtPass.Text,
                Role = role
            };

            if (!repo.UpdateUser(u)) MessageBox.Show("Cập nhật thất bại.");
            LoadUsers();
        }

        private void BtnDelete_Click(object sender, EventArgs e)
        {
            if (string.IsNullOrWhiteSpace(txtUser.Text)) return;
            if (MessageBox.Show($"Xóa tài khoản {txtUser.Text}?", "Xóa", MessageBoxButtons.YesNo) == DialogResult.Yes)
            {
                repo.RemoveUser(txtUser.Text.Trim());
                txtUser.Text = txtPass.Text = "";
                cboRole.SelectedIndex = 0;
                LoadUsers();
            }
        }
    }
}


