## **Step 3: Validators.cs - Email & Phone Validation**

```csharp name=HRManagement.Utils/Validators.cs
using System;
using System.Net.Mail;
using System.Text.RegularExpressions;

namespace HRManagement.Utils
{
    /// <summary>
    /// Utilities for validating user input formats.
    /// </summary>
    public static class Validators
    {
        /// <summary>
        /// Validates email format using System.Net.Mail (strict validation).
        /// </summary>
        public static bool IsValidEmail(string email)
        {
            if (string.IsNullOrWhiteSpace(email))
                return false;

            try
            {
                // System.Net.Mail validates format; will throw FormatException if invalid
                var addr = new MailAddress(email);
                return addr.Address == email.Trim();
            }
            catch (FormatException)
            {
                return false;
            }
            catch
            {
                return false;
            }
        }

        /// <summary>
        /// Validates phone number format (Vietnam: 10-11 digits, can start with 0, +84, etc).
        /// Also accepts patterns like: 0123456789, +84123456789, (84) 123 456 789
        /// </summary>
        public static bool IsValidPhoneNumber(string phone)
        {
            if (string.IsNullOrWhiteSpace(phone))
                return false;

            // Remove common formatting characters
            string cleaned = Regex.Replace(phone, @"[\s\-\(\)\+]", "");

            // Phone should be 10-11 digits
            if (cleaned.Length < 10 || cleaned.Length > 11)
                return false;

            // Must contain only digits (after cleaning)
            return Regex.IsMatch(cleaned, @"^\d+$");
        }

        /// <summary>
        /// Validates employee ID format (typically alphanumeric, e.g., E001, EMP-001)
        /// </summary>
        public static bool IsValidEmployeeId(string employeeId)
        {
            if (string.IsNullOrWhiteSpace(employeeId))
                return false;

            // Allow letters, numbers, hyphens; length 3-20
            return Regex.IsMatch(employeeId, @"^[A-Z0-9\-]{3,20}$", RegexOptions.IgnoreCase);
        }

        /// <summary>
        /// Validates Vietnamese name (allows letters, spaces, hyphens; 2-100 chars)
        /// </summary>
        public static bool IsValidFullName(string fullName)
        {
            if (string.IsNullOrWhiteSpace(fullName))
                return false;

            fullName = fullName.Trim();
            if (fullName.Length < 2 || fullName.Length > 100)
                return false;

            // Allow Vietnamese characters, spaces, hyphens
            return Regex.IsMatch(fullName, @"^[\p{L}\s\-']{2,100}$");
        }

        /// <summary>
        /// Validates username (alphanumeric and underscore, 3-20 chars)
        /// </summary>
        public static bool IsValidUsername(string username)
        {
            if (string.IsNullOrWhiteSpace(username))
                return false;

            return Regex.IsMatch(username, @"^[a-zA-Z0-9_]{3,20}$");
        }

        /// <summary>
        /// Validates password strength (min 6 chars, should contain uppercase, lowercase, digit)
        /// </summary>
        public static (bool IsValid, string Message) IsValidPassword(string password)
        {
            if (string.IsNullOrWhiteSpace(password))
                return (false, "Mật khẩu không được để trống");

            if (password.Length < 6)
                return (false, "Mật khẩu phải có ít nhất 6 ký tự");

            if (!Regex.IsMatch(password, @"[A-Z]"))
                return (false, "Mật khẩu phải chứa ít nhất một chữ hoa");

            if (!Regex.IsMatch(password, @"[a-z]"))
                return (false, "Mật khẩu phải chứa ít nhất một chữ thường");

            if (!Regex.IsMatch(password, @"[0-9]"))
                return (false, "Mật khẩu phải chứa ít nhất một số");

            return (true, "OK");
        }
    }
}
