## **Step 4: Encryption.cs - Password Hashing**

```csharp name=HRManagement.Utils/Encryption.cs
using BCrypt.Net;
using System;

namespace HRManagement.Utils
{
    /// <summary>
    /// Password hashing and verification using bcrypt.
    /// IMPORTANT: Install NuGet package BCrypt.Net-Next before using.
    /// </summary>
    public static class Encryption
    {
        /// <summary>
        /// Hashes a plain text password using bcrypt with configurable work factor.
        /// </summary>
        /// <param name="password">Plain text password</param>
        /// <param name="workFactor">Cost factor (10-12 recommended; higher = slower but more secure)</param>
        /// <returns>Bcrypt hashed password</returns>
        public static string HashPassword(string password, int workFactor = 12)
        {
            if (string.IsNullOrWhiteSpace(password))
                throw new ArgumentException("Password cannot be null or empty", nameof(password));

            try
            {
                return BCrypt.EnhancedHashPassword(password, workFactor);
            }
            catch (Exception ex)
            {
                throw new InvalidOperationException("Error hashing password", ex);
            }
        }

        /// <summary>
        /// Verifies a plain text password against a bcrypt hash.
        /// Uses constant-time comparison to prevent timing attacks.
        /// </summary>
        /// <param name="password">Plain text password to verify</param>
        /// <param name="hash">Bcrypt hash to verify against</param>
        /// <returns>True if password matches hash, false otherwise</returns>
        public static bool VerifyPassword(string password, string hash)
        {
            if (string.IsNullOrWhiteSpace(password) || string.IsNullOrWhiteSpace(hash))
                return false;

            try
            {
                return BCrypt.EnhancedVerify(password, hash);
            }
            catch
            {
                // Log the error but return false (don't expose hash format details)
                return false;
            }
        }

        /// <summary>
        /// Checks if a password hash needs to be upgraded (e.g., work factor changed)
        /// </summary>
        public static bool NeedsPasswordUpgrade(string hash, int currentWorkFactor = 12)
        {
            if (string.IsNullOrWhiteSpace(hash))
                return true;

            try
            {
                // Extract work factor from hash (bcrypt format: $2a$10$...)
                // Cost is the number after second $
                var parts = hash.Split('$');
                if (parts.Length < 4)
                    return true;

                int storedWorkFactor = int.Parse(parts[2]);
                return storedWorkFactor < currentWorkFactor;
            }
            catch
            {
                return true;
            }
        }
    }
}
```

