## **Step 5: Logger.cs - Logging System**

```csharp name=HRManagement.Utils/Logger.cs
using System;
using System.IO;

namespace HRManagement.Utils
{
    /// <summary>
    /// Simple file-based logging system.
    /// For production, consider using NLog or Serilog.
    /// </summary>
    public static class Logger
    {
        private static readonly string LogDirectory = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "logs");
        private static readonly object LockObject = new object();

        static Logger()
        {
            // Ensure logs directory exists
            if (!Directory.Exists(LogDirectory))
                Directory.CreateDirectory(LogDirectory);
        }

        /// <summary>
        /// Gets the current log file path (daily rotation)
        /// </summary>
        private static string GetLogFilePath()
        {
            string filename = $"app_{DateTime.Now:yyyy-MM-dd}.log";
            return Path.Combine(LogDirectory, filename);
        }

        /// <summary>
        /// Logs an information message
        /// </summary>
        public static void LogInfo(string message)
        {
            WriteLog("INFO", message);
        }

        /// <summary>
        /// Logs a warning message
        /// </summary>
        public static void LogWarn(string message)
        {
            WriteLog("WARN", message);
        }

        /// <summary>
        /// Logs an error message with optional exception details
        /// </summary>
        public static void LogError(string message, Exception ex = null)
        {
            string fullMessage = ex == null 
                ? message 
                : $"{message}\nException: {ex.GetType().Name}\nMessage: {ex.Message}\nStackTrace: {ex.StackTrace}";
            WriteLog("ERROR", fullMessage);
        }

        /// <summary>
        /// Logs a debug message
        /// </summary>
        public static void LogDebug(string message)
        {
#if DEBUG
            WriteLog("DEBUG", message);
#endif
        }

        /// <summary>
        /// Logs security-related events (logins, permission changes, etc.)
        /// IMPORTANT: Never log passwords or sensitive data!
        /// </summary>
        public static void LogSecurity(string message)
        {
            WriteLog("SECURITY", message);
        }

        /// <summary>
        /// Internal method to write to log file with thread-safe locking
        /// </summary>
        private static void WriteLog(string level, string message)
        {
            lock (LockObject)
            {
                try
                {
                    string logPath = GetLogFilePath();
                    string timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss.fff");
                    string logEntry = $"[{timestamp}] [{level}] {message}{Environment.NewLine}";

                    File.AppendAllText(logPath, logEntry);
                }
                catch
                {
                    // Silently fail if logging itself fails (to avoid infinite recursion)
                    System.Diagnostics.Debug.WriteLine($"Logging failed: {message}");
                }
            }
        }

        /// <summary>
        /// Clears old log files (older than specified days)
        /// </summary>
        public static void CleanOldLogs(int daysToKeep = 30)
        {
            try
            {
                var di = new DirectoryInfo(LogDirectory);
                foreach (var file in di.GetFiles("app_*.log"))
                {
                    if ((DateTime.Now - file.CreationTime).TotalDays > daysToKeep)
                        file.Delete();
                }
            }
            catch (Exception ex)
            {
                LogError("Error cleaning old logs", ex);
            }
        }
    }
}
```

