        // ===================== HELPERS =====================

        private int? GetDepartmentIdByName(string departmentName)
        {
            if (string.IsNullOrWhiteSpace(departmentName))
                return null;

            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("SELECT DepartmentId FROM Departments WHERE DepartmentName = @Name", cn))
                {
                    cmd.Parameters.AddWithValue("@Name", departmentName);
                    cn.Open();
                    var result = cmd.ExecuteScalar();
                    return result == null ? (int?)null : Convert.ToInt32(result);
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error getting department ID for: {departmentName}", ex);
                return null;
            }
        }

