            return new User
            {
                Username = dr["Username"] as string,
                PasswordHash = dr["PasswordHash"] as string,
                Role = Enum.TryParse<UserRole>(dr["Role"]?.ToString() ?? "Staff", true, out var role) 
                    ? role 
                    : UserRole.Staff,
                IsActive = dr["IsActive"] is bool b ? b : (dr["IsActive"] is int i ? i == 1 : false),
                CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now,
                LastLogin = dr["LastLogin"] as DateTime?
            };
        }

        private Employee MapRowToEmployee(IDataRecord dr)
        {
            return new Employee
            {
                EmployeeId = dr["EmployeeId"] as string,
                FullName = dr["FullName"] as string,
                BirthDate = dr["BirthDate"] as DateTime?,
                Gender = dr["Gender"] as string,
                Department = dr["DepartmentName"] as string,
                Phone = dr["Phone"] as string,
                Email = dr["Email"] as string,
                CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now,
                UpdatedAt = dr["UpdatedAt"] as DateTime?
            };
        }

        public void Dispose()
        {
            // SqlConnection is closed automatically when using 'using' statement
        }
    }
}
