## **3. Tạo repository mới cho SQL: `SqlRepository.cs`**

```csharp name=HRManagement.Repository/SqlRepository.cs
using HRManagement.Models;
using HRManagement.Utils;
using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;

namespace HRManagement.Repository
{
    public class SqlRepository : IRepository
    {
        private readonly string _connStr;

        public SqlRepository(string connectionString)
        {
            _connStr = connectionString ?? throw new ArgumentNullException(nameof(connectionString));
        }

        // ============ USER ==============
        public User ValidateUser(string username, string password)
        {
            var user = GetUserByUsername(username);
            if (user == null) return null;
            if (!Encryption.VerifyPassword(password, user.PasswordHash)) return null;

            // Update last login
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("UPDATE Users SET LastLogin=GETDATE() WHERE Username=@Username", cn))
                {
                    cmd.Parameters.AddWithValue("@Username", username);
                    cn.Open();
                    cmd.ExecuteNonQuery();
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Update last login failed for {username}", ex);
            }
            return user;
        }

        public User GetUserByUsername(string username)
        {
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("SELECT Username, PasswordHash, Role, IsActive, CreatedAt, LastLogin FROM Users WHERE Username=@u", cn))
                {
                    cmd.Parameters.AddWithValue("@u", username);
                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        if (!dr.Read()) return null;
                        return new User
                        {
                            Username = dr["Username"] as string,
                            PasswordHash = dr["PasswordHash"] as string,
                            Role = Enum.TryParse<UserRole>(dr["Role"]?.ToString(), true, out var r) ? r : UserRole.Staff,
                            IsActive = (bool)dr["IsActive"],
                            CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now,
                            LastLogin = dr["LastLogin"] as DateTime?
                        };
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"GetUserByUsername error: {username}", ex);
                return null;
            }
        }

        public bool AddUser(User user)
        {
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("INSERT INTO Users (Username, PasswordHash, Role, IsActive, CreatedAt) VALUES (@u, @p, @r, @a, GETDATE())", cn))
                {
                    cmd.Parameters.AddWithValue("@u", user.Username);
                    cmd.Parameters.AddWithValue("@p", user.PasswordHash);
                    cmd.Parameters.AddWithValue("@r", user.Role.ToString());
                    cmd.Parameters.AddWithValue("@a", user.IsActive ? 1 : 0);
                    cn.Open();
                    return cmd.ExecuteNonQuery() > 0;
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"AddUser failed: {user.Username}", ex);
                return false;
            }
        }

        public bool UpdateUser(User user)
        {
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("UPDATE Users SET PasswordHash=@p, Role=@r, IsActive=@a WHERE Username=@u", cn))
                {
                    cmd.Parameters.AddWithValue("@p", user.PasswordHash);
                    cmd.Parameters.AddWithValue("@r", user.Role.ToString());
                    cmd.Parameters.AddWithValue("@a", user.IsActive ? 1 : 0);
                    cmd.Parameters.AddWithValue("@u", user.Username);
                    cn.Open();
                    return cmd.ExecuteNonQuery() > 0;
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"UpdateUser failed: {user.Username}", ex);
                return false;
            }
        }

        public bool RemoveUser(string username)
        {
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("DELETE FROM Users WHERE Username=@u", cn))
                {
                    cmd.Parameters.AddWithValue("@u", username);
                    cn.Open();
                    return cmd.ExecuteNonQuery() > 0;
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"RemoveUser failed: {username}", ex);
                return false;
            }
        }

        public IEnumerable<User> GetAllUsers()
        {
            var list = new List<User>();
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("SELECT Username, PasswordHash, Role, IsActive, CreatedAt, LastLogin FROM Users", cn))
                {
                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        while (dr.Read())
                        {
                            list.Add(new User
                            {
                                Username = dr["Username"] as string,
                                PasswordHash = dr["PasswordHash"] as string,
                                Role = Enum.TryParse<UserRole>(dr["Role"]?.ToString(), true, out var r) ? r : UserRole.Staff,
                                IsActive = (bool)dr["IsActive"],
                                CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now,
                                LastLogin = dr["LastLogin"] as DateTime?
                            });
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("GetAllUsers error", ex);
            }
            return list;
        }

        // ============ EMPLOYEE ==============
        public Employee GetEmployeeById(string id)
        {
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("SELECT e.EmployeeId, e.FullName, e.BirthDate, e.Gender, d.DepartmentName, e.Phone, e.Email, e.CreatedAt, e.UpdatedAt FROM Employees e LEFT JOIN Departments d ON e.DepartmentId = d.DepartmentId WHERE e.EmployeeId = @id", cn))
                {
                    cmd.Parameters.AddWithValue("@id", id);
                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        if (!dr.Read()) return null;
                        return new Employee
                        {
                            EmployeeId = dr["EmployeeId"] as string,
                            FullName = dr["FullName"] as string,
                            BirthDate = dr["BirthDate"] as DateTime?,
                            Gender = dr["Gender"] as string,
                            Department = dr["DepartmentName"] as string,
                            Phone = dr["Phone"] as string,
                            Email = dr["Email"] as string,
                            CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now,
                            UpdatedAt = dr["UpdatedAt"] as DateTime?
                        };
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("GetEmployeeById error", ex);
                return null;
            }
        }

        public bool AddEmployee(Employee e)
        {
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("usp_InsertEmployee", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@EmployeeId", e.EmployeeId);
                    cmd.Parameters.AddWithValue("@FullName", e.FullName);
                    cmd.Parameters.AddWithValue("@BirthDate", (object)e.BirthDate ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Gender", (object)e.Gender ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@DepartmentId", DepartmentNameToId(e.Department));
                    cmd.Parameters.AddWithValue("@Phone", (object)e.Phone ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Email", (object)e.Email ?? DBNull.Value);
                    cn.Open();
                    return cmd.ExecuteNonQuery() > 0;
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("AddEmployee error", ex);
                return false;
            }
        }

        public bool UpdateEmployee(Employee e)
        {
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("usp_UpdateEmployee", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@EmployeeId", e.EmployeeId);
                    cmd.Parameters.AddWithValue("@FullName", e.FullName);
                    cmd.Parameters.AddWithValue("@BirthDate", (object)e.BirthDate ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Gender", (object)e.Gender ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@DepartmentId", DepartmentNameToId(e.Department));
                    cmd.Parameters.AddWithValue("@Phone", (object)e.Phone ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Email", (object)e.Email ?? DBNull.Value);
                    cn.Open();
                    return cmd.ExecuteNonQuery() > 0;
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("UpdateEmployee error", ex);
                return false;
            }
        }

        public bool RemoveEmployee(string id)
        {
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("usp_DeleteEmployee", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@EmployeeId", id);
                    cn.Open();
                    return cmd.ExecuteNonQuery() > 0;
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("RemoveEmployee error", ex);
                return false;
            }
        }

        public IEnumerable<Employee> SearchEmployees(string name, string gender, DateTime? dob, string id)
        {
            var results = new List<Employee>();
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("usp_SearchEmployees", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@Name", (object)name ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Gender", (object)gender ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@BirthDate", (object)dob ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@EmployeeId", (object)id ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@DepartmentId", DBNull.Value);

                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        while (dr.Read())
                        {
                            results.Add(new Employee
                            {
                                EmployeeId = dr["EmployeeId"] as string,
                                FullName = dr["FullName"] as string,
                                BirthDate = dr["BirthDate"] as DateTime?,
                                Gender = dr["Gender"] as string,
                                Department = dr["DepartmentName"] as string,
                                Phone = dr["Phone"] as string,
                                Email = dr["Email"] as string
                            });
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("SearchEmployees error", ex);
            }
            return results;
        }

        public IEnumerable<Employee> GetAllEmployees()
        {
            var results = new List<Employee>();
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("SELECT e.EmployeeId, e.FullName, e.BirthDate, e.Gender, d.DepartmentName, e.Phone, e.Email, e.CreatedAt, e.UpdatedAt FROM Employees e LEFT JOIN Departments d ON e.DepartmentId = d.DepartmentId", cn))
                {
                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        while (dr.Read())
                        {
                            results.Add(new Employee
                            {
                                EmployeeId = dr["EmployeeId"] as string,
                                FullName = dr["FullName"] as string,
                                BirthDate = dr["BirthDate"] as DateTime?,
                                Gender = dr["Gender"] as string,
                                Department = dr["DepartmentName"] as string,
                                Phone = dr["Phone"] as string,
                                Email = dr["Email"] as string,
                                CreatedAt = dr["CreatedAt"] as DateTime?,
                                UpdatedAt = dr["UpdatedAt"] as DateTime?
                            });
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("GetAllEmployees error", ex);
            }
            return results;
        }

        public void Dispose()
        {
            // Nothing to dispose for now
        }

        /// <summary>
        /// Helper: Lấy DepartmentId từ tên phòng ban
        /// </summary>
        private int? DepartmentNameToId(string departmentName)
        {
            if (string.IsNullOrWhiteSpace(departmentName)) return null;
            try
            {
                using (var cn = new SqlConnection(_connStr))
                using (var cmd = new SqlCommand("SELECT DepartmentId FROM Departments WHERE DepartmentName=@Name", cn))
                {
                    cmd.Parameters.AddWithValue("@Name", departmentName);
                    cn.Open();
                    var id = cmd.ExecuteScalar();
                    return id == null ? (int?)null : Convert.ToInt32(id);
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("DepartmentNameToId error", ex);
                return null;
            }
        }
    }
}
