using HRManagement.Models;
using HRManagement.Utils;
using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;

namespace HRManagement.Repository
{
    /// <summary>
    /// Extension methods for SqlRepository to handle Phase 3 features
    /// Add these methods to the existing SqlRepository class
    /// </summary>
    public partial class SqlRepository
    {
        // ===================== DEPARTMENTS =====================

        public Department GetDepartmentById(int id)
        {
            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_GetDepartmentById", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@DepartmentId", id);

                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        if (!dr.Read()) return null;
                        return new Department
                        {
                            DepartmentId = (int)dr["DepartmentId"],
                            DepartmentName = dr["DepartmentName"] as string,
                            Description = dr["Description"] as string,
                            CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now
                        };
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error getting department {id}", ex);
                return null;
            }
        }

        public IEnumerable<Department> GetAllDepartments()
        {
            var departments = new List<Department>();
            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_GetAllDepartments", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;

                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        while (dr.Read())
                        {
                            departments.Add(new Department
                            {
                                DepartmentId = (int)dr["DepartmentId"],
                                DepartmentName = dr["DepartmentName"] as string,
                                Description = dr["Description"] as string,
                                CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now
                            });
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error getting all departments", ex);
            }
            return departments;
        }

        public bool AddDepartment(Department dept)
        {
            try
            {
                if (dept == null || string.IsNullOrWhiteSpace(dept.DepartmentName))
                {
                    Logger.LogWarn("Attempt to add null or invalid department");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_InsertDepartment", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@DepartmentName", dept.DepartmentName);
                    cmd.Parameters.AddWithValue("@Description", (object)dept.Description ?? DBNull.Value);

                    cn.Open();
                    cmd.ExecuteNonQuery();
                    Logger.LogInfo($"Department added: {dept.DepartmentName}");
                    return true;
                }
            }
            catch (SqlException ex) when (ex.Number == 50000)
            {
                Logger.LogWarn($"Department already exists: {dept.DepartmentName}");
                return false;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error adding department", ex);
                return false;
            }
        }

        public bool UpdateDepartment(Department dept)
        {
            try
            {
                if (dept == null || string.IsNullOrWhiteSpace(dept.DepartmentName))
                {
                    Logger.LogWarn("Attempt to update null or invalid department");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_UpdateDepartment", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@DepartmentId", dept.DepartmentId);
                    cmd.Parameters.AddWithValue("@DepartmentName", dept.DepartmentName);
                    cmd.Parameters.AddWithValue("@Description", (object)dept.Description ?? DBNull.Value);

                    cn.Open();
                    cmd.ExecuteNonQuery();
                    Logger.LogInfo($"Department updated: {dept.DepartmentName}");
                    return true;
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error updating department", ex);
                return false;
            }
        }

        public bool DeleteDepartment(int deptId)
        {
            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_DeleteDepartment", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@DepartmentId", deptId);

                    cn.Open();
                    cmd.ExecuteNonQuery();
                    Logger.LogInfo($"Department deleted: {deptId}");
                    return true;
                }
            }
            catch (SqlException ex) when (ex.Number == 50000)
            {
                Logger.LogWarn($"Cannot delete department with active employees");
                return false;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error deleting department", ex);
                return false;
            }
        }

        // ===================== SALARY =====================

        public bool AddSalary(Salary salary, string createdBy)
        {
            try
            {
                if (salary == null || string.IsNullOrWhiteSpace(salary.EmployeeId))
                {
                    Logger.LogWarn("Attempt to add null or invalid salary");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_InsertSalary", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@EmployeeId", salary.EmployeeId);
                    cmd.Parameters.AddWithValue("@BaseSalary", salary.BaseSalary);
                    cmd.Parameters.AddWithValue("@Allowance", salary.Allowance);
                    cmd.Parameters.AddWithValue("@Deduction", salary.Deduction);
                    cmd.Parameters.AddWithValue("@EffectiveDate", salary.EffectiveDate.Date);
                    cmd.Parameters.AddWithValue("@Remark", (object)salary.Remark ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@CreatedBy", createdBy);

                    cn.Open();
                    cmd.ExecuteNonQuery();
                    Logger.LogInfo($"Salary record added for employee: {salary.EmployeeId}");
                    return true;
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error adding salary for {salary?.EmployeeId}", ex);
                return false;
            }
        }

        public Salary GetCurrentSalary(string employeeId)
        {
            try
            {
                using (var cn = new SqlConnection(_connectionString))
