using System;
using System.Collections.Generic;
using System.Linq;
using HRManagement.Models;
using HRManagement.Utils;

namespace HRManagement.Repository
{
    /// <summary>
    /// In-memory repository implementation.
    /// NOTE: Data is lost when application closes. Use SqlRepository for persistence.
    /// </summary>
    public class InMemoryRepository : IRepository
    {
        private readonly List<User> _users = new List<User>();
        private readonly List<Employee> _employees = new List<Employee>();

        public IReadOnlyList<User> Users => _users.AsReadOnly();
        public IReadOnlyList<Employee> Employees => _employees.AsReadOnly();

        public InMemoryRepository()
        {
            InitializeSampleData();
        }

        private void InitializeSampleData()
        {
            try
            {
                // Sample users with HASHED passwords
                _users.Add(new User
                {
                    Username = "admin",
                    PasswordHash = Encryption.HashPassword("Admin123"),
                    Role = UserRole.Admin,
                    IsActive = true,
                    CreatedAt = DateTime.Now
                });

                _users.Add(new User
                {
                    Username = "staff",
                    PasswordHash = Encryption.HashPassword("Staff123"),
                    Role = UserRole.Staff,
                    IsActive = true,
                    CreatedAt = DateTime.Now
                });

                // Sample employees
                _employees.Add(new Employee
                {
                    EmployeeId = "E001",
                    FullName = "Nguyễn Văn A",
                    BirthDate = new DateTime(1990, 1, 1),
                    Gender = "Nam",
                    Department = "Kỹ thuật",
                    Phone = "0123456789",
                    Email = "a@example.com",
                    CreatedAt = DateTime.Now
                });

                _employees.Add(new Employee
                {
                    EmployeeId = "E002",
                    FullName = "Trần Thị B",
                    BirthDate = new DateTime(1992, 2, 2),
                    Gender = "Nữ",
                    Department = "Kế toán",
                    Phone = "0987654321",
                    Email = "b@example.com",
                    CreatedAt = DateTime.Now
                });

                Logger.LogInfo("Sample data initialized successfully");
            }
            catch (Exception ex)
            {
                Logger.LogError("Error initializing sample data", ex);
                throw;
            }
        }

        // ============ USERS ============

        public User ValidateUser(string username, string password)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(username) || string.IsNullOrWhiteSpace(password))
                    return null;

                var user = _users.FirstOrDefault(u => u.Username == username && u.IsActive);
                if (user == null)
                {
                    Logger.LogSecurity($"Failed login attempt for username: {username}");
                    return null;
                }

                // Verify password hash
                if (!Encryption.VerifyPassword(password, user.PasswordHash))
                {
                    Logger.LogSecurity($"Failed login attempt (wrong password) for username: {username}");
                    return null;
                }

                // Update last login
                user.LastLogin = DateTime.Now;
                Logger.LogSecurity($"User logged in: {username}");
                return user;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error validating user {username}", ex);
                return null;
            }
        }

        public User GetUserByUsername(string username)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(username))
                    return null;

                return _users.FirstOrDefault(u => u.Username == username);
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error getting user {username}", ex);
                return null;
            }
        }

        public bool AddUser(User user)
        {
            try
            {
                if (user == null || string.IsNullOrWhiteSpace(user.Username))
                {
                    Logger.LogWarn("Attempt to add null or invalid user");
                    return false;
                }

                if (_users.Any(x => x.Username == user.Username))
                {
                    Logger.LogWarn($"User already exists: {user.Username}");
                    return false;
                }

                _users.Add(user);
                Logger.LogInfo($"User added: {user.Username}");
                return true;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error adding user {user?.Username}", ex);
                return false;
            }
        }

        public bool UpdateUser(User user)
        {
            try
            {
                if (user == null || string.IsNullOrWhiteSpace(user.Username))
                {
                    Logger.LogWarn("Attempt to update null or invalid user");
                    return false;
                }

                var existing = _users.FirstOrDefault(x => x.Username == user.Username);
                if (existing == null)
                {
                    Logger.LogWarn($"User not found for update: {user.Username}");
                    return false;
                }

                existing.PasswordHash = user.PasswordHash;
                existing.Role = user.Role;
                existing.IsActive = user.IsActive;
                existing.UpdatedAt = DateTime.Now;

                Logger.LogInfo($"User updated: {user.Username}");
                return true;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error updating user {user?.Username}", ex);
                return false;
            }
        }

        public bool RemoveUser(string username)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(username))
                {
                    Logger.LogWarn("Attempt to remove user with null username");
                    return false;
                }

                var user = _users.FirstOrDefault(x => x.Username == username);
                if (user == null)
                {
                    Logger.LogWarn($"User not found for deletion: {username}");
                    return false;
                }

                _users.Remove(user);
                Logger.LogInfo($"User deleted: {username}");
                return true;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error removing user {username}", ex);
                return false;
            }
        }

        public IEnumerable<User> GetAllUsers()
        {
            return _users.ToList();
        }

        // ============ EMPLOYEES ============

        public Employee GetEmployeeById(string id)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(id))
                    return null;

                return _employees.FirstOrDefault(x => x.EmployeeId == id);
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error getting employee {id}", ex);
                return null;
            }
        }

        public bool AddEmployee(Employee employee)
        {
            try
            {
                if (employee == null || string.IsNullOrWhiteSpace(employee.EmployeeId))
                {
                    Logger.LogWarn("Attempt to add null or invalid employee");
                    return false;
                }

                if (_employees.Any(x => x.EmployeeId == employee.EmployeeId))
                {
                    Logger.LogWarn($"Employee already exists: {employee.EmployeeId}");
                    return false;
                }

                _employees.Add(employee);
                Logger.LogInfo($"Employee added: {employee.EmployeeId} - {employee.FullName}");
                return true;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error adding employee {employee?.EmployeeId}", ex);
                return false;
            }
        }

        public bool UpdateEmployee(Employee employee)
        {
            try
            {
                if (employee == null || string.IsNullOrWhiteSpace(employee.EmployeeId))
                {
                    Logger.LogWarn("Attempt to update null or invalid employee");
                    return false;
                }

                var existing = _employees.FirstOrDefault(x => x.EmployeeId == employee.EmployeeId);
                if (existing == null)
                {
                    Logger.LogWarn($"Employee not found for update: {employee.EmployeeId}");
                    return false;
                }

                existing.FullName = employee.FullName;
                existing.BirthDate = employee.BirthDate;
                existing.Gender = employee.Gender;
                existing.Department = employee.Department;
                existing.Phone = employee.Phone;
                existing.Email = employee.Email;
                existing.UpdatedAt = DateTime.Now;

                Logger.LogInfo($"Employee updated: {employee.EmployeeId}");
                return true;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error updating employee {employee?.EmployeeId}", ex);
                return false;
            }
        }

        public bool RemoveEmployee(string id)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(id))
                {
                    Logger.LogWarn("Attempt to remove employee with null ID");
                    return false;
                }

                var employee = _employees.FirstOrDefault(x => x.EmployeeId == id);
                if (employee == null)
                {
                    Logger.LogWarn($"Employee not found for deletion: {id}");
                    return false;
                }

                _employees.Remove(employee);
                Logger.LogInfo($"Employee deleted: {id}");
                return true;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error removing employee {id}", ex);
                return false;
            }
        }

        public IEnumerable<Employee> GetAllEmployees()
        {
            return _employees.ToList();
        }

        public IEnumerable<Employee> SearchEmployees(string name, string gender, DateTime? dob, string id)
        {
            try
            {
                var query = _employees.AsEnumerable();

                if (!string.IsNullOrWhiteSpace(name))
                    query = query.Where(x => x.FullName.IndexOf(name, StringComparison.OrdinalIgnoreCase) >= 0);

                if (!string.IsNullOrWhiteSpace(gender))
                    query = query.Where(x => x.Gender == gender);

                if (dob.HasValue)
                    query = query.Where(x => x.BirthDate?.Date == dob.Value.Date);

                if (!string.IsNullOrWhiteSpace(id))
                    query = query.Where(x => x.EmployeeId.IndexOf(id, StringComparison.OrdinalIgnoreCase) >= 0);

                return query.ToList();
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error searching employees", ex);
                return new List<Employee>();
            }
        }

        public void Dispose()
        {
            // Cleanup if needed
            _users?.Clear();
            _employees?.Clear();
        }
    }
}

