            FormBorderStyle = FormBorderStyle.FixedSingle;
            MaximizeBox = false;

            InitializeComponent();
            InitializeCustomComponents();
        }

        private void InitializeCustomComponents()
        {
            Label lblUser = new Label
            {
                Text = "Tài khoản",
                Location = new Point(20, 20),
                AutoSize = true,
                Font = new Font("Tahoma", 12)
            };
            txtUser = new TextBox { Location = new Point(140, 20), Width = 220 };

            Label lblPass = new Label
            {
                Text = "Mật khẩu",
                Location = new Point(20, 60),
                AutoSize = true,
                Font = new Font("Tahoma", 12)
            };
            txtPass = new TextBox
            {
                Location = new Point(140, 60),
                Width = 220,
                UseSystemPasswordChar = true
            };

            chkShow = new CheckBox
            {
                Text = "Hiển thị mật khẩu",
                Location = new Point(140, 90),
                AutoSize = true
            };
            chkShow.CheckedChanged += (s, e) => txtPass.UseSystemPasswordChar = !chkShow.Checked;

            btnLogin = new Button { Text = "Đăng nhập", Location = new Point(140, 120), Width = 100 };
            btnExit = new Button { Text = "Thoát", Location = new Point(260, 120), Width = 100 };

            btnLogin.Click += BtnLogin_Click;
            btnExit.Click += (s, e) => Application.Exit();

            AcceptButton = btnLogin;
            CancelButton = btnExit;

            Controls.AddRange(new Control[] { lblUser, txtUser, lblPass, txtPass, chkShow, btnLogin, btnExit });
        }

        private void BtnLogin_Click(object sender, EventArgs e)
        {
            try
            {
                var username = txtUser.Text?.Trim();
                var password = txtPass.Text ?? string.Empty;

                if (string.IsNullOrWhiteSpace(username))
                {
                    MessageBox.Show("Vui lòng nhập tên đăng nhập.", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtUser.Focus();
                    return;
                }

                if (string.IsNullOrWhiteSpace(password))
                {
                    MessageBox.Show("Vui lòng nhập mật khẩu.", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtPass.Focus();
                    return;
                }

                // Validate user credentials
                var user = repo.ValidateUser(username, password);
                if (user != null)
                {
                    Logger.LogSecurity($"Login successful for user: {username}");
                    var main = new FormMain(repo, user);
                    Hide();
                    main.FormClosed += (s, ev) => Close();
                    main.Show();
                }
                else
                {
                    Logger.LogSecurity($"Login failed for user: {username}");
                    MessageBox.Show("Sai tên đăng nhập hoặc mật khẩu", "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtPass.SelectAll();
                    txtPass.Focus();
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error in login process", ex);
                MessageBox.Show("Lỗi đăng nhập: " + ex.Message, "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
    }
}

