            Label lGender = new Label { Text = "Giới tính", Location = new Point(20, 140), AutoSize = true };
            cboGender = new ComboBox { Location = new Point(140, 136), Width = 120, DropDownStyle = ComboBoxStyle.DropDownList };
            cboGender.Items.AddRange(Constants.Genders);

            Label lDept = new Label { Text = "Phòng ban", Location = new Point(20, 180), AutoSize = true };
            cboDept = new ComboBox { Location = new Point(140, 178), Width = 220, DropDownStyle = ComboBoxStyle.DropDownList };
            cboDept.Items.AddRange(Constants.Departments);

            Label lPhone = new Label { Text = "Điện thoại", Location = new Point(20, 220), AutoSize = true };
            txtPhone = new TextBox { Location = new Point(140, 218), Width = 220 };

            Label lEmail = new Label { Text = "Email", Location = new Point(20, 260), AutoSize = true };
            txtEmail = new TextBox { Location = new Point(140, 258), Width = 220 };

            btnSave = new Button { Text = "Lưu", Location = new Point(140, 295), Width = 80 };
            btnCancel = new Button { Text = "Hủy", Location = new Point(240, 295), Width = 80 };

            btnSave.Click += BtnSave_Click;
            btnCancel.Click += (s, e) => Close();

            Controls.AddRange(new Control[] { lId, txtId, lName, txtName, lDob, dtpDob, lGender, cboGender, lDept, cboDept, lPhone, txtPhone, lEmail, txtEmail, btnSave, btnCancel });
        }

        void LoadEmployee()
        {
            txtId.Text = editEmployee.EmployeeId;
            txtId.Enabled = false;
            txtName.Text = editEmployee.FullName;
            if (editEmployee.BirthDate.HasValue) dtpDob.Value = editEmployee.BirthDate.Value;
            cboGender.Text = editEmployee.Gender;
            cboDept.Text = editEmployee.Department;
            txtPhone.Text = editEmployee.Phone;
            txtEmail.Text = editEmployee.Email;
        }

        void BtnSave_Click(object sender, EventArgs e)
        {
            try
            {
                // Validation
                if (string.IsNullOrWhiteSpace(txtId.Text))
                {
                    MessageBox.Show("Mã nhân viên bắt buộc.", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtId.Focus();
                    return;
                }

                if (!Validators.IsValidEmployeeId(txtId.Text))
                {
                    MessageBox.Show("Mã nhân viên không hợp lệ (chỉ chứa chữ, số, dấu gạch ngang).", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtId.Focus();
                    return;
                }

                if (string.IsNullOrWhiteSpace(txtName.Text))
                {
                    MessageBox.Show("Họ tên bắt buộc.", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtName.Focus();
                    return;
                }

                if (!Validators.IsValidFullName(txtName.Text))
                {
                    MessageBox.Show("Họ tên không hợp lệ (2-100 ký tự).", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtName.Focus();
                    return;
                }

                if (!string.IsNullOrWhiteSpace(txtPhone.Text) && !Validators.IsValidPhoneNumber(txtPhone.Text))
                {
                    MessageBox.Show("Số điện thoại không hợp l��� (10-11 chữ số).", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtPhone.Focus();
                    return;
                }

                if (!string.IsNullOrWhiteSpace(txtEmail.Text) && !Validators.IsValidEmail(txtEmail.Text))
                {
                    MessageBox.Show("Email không hợp lệ.", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    txtEmail.Focus();
                    return;
                }

                if (cboGender.SelectedIndex < 0)
                {
                    MessageBox.Show("Vui lòng chọn giới tính.", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    cboGender.Focus();
                    return;
                }

                if (cboDept.SelectedIndex < 0)
                {
                    MessageBox.Show("Vui lòng chọn phòng ban.", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    cboDept.Focus();
                    return;
                }

                var emp = new Employee
                {
                    EmployeeId = txtId.Text.Trim(),
                    FullName = txtName.Text.Trim(),
                    BirthDate = dtpDob.Value,
                    Gender = cboGender.Text,
                    Department = cboDept.Text,
                    Phone = txtPhone.Text.Trim(),
                    Email = txtEmail.Text.Trim()
                };

                bool ok;
                if (editEmployee == null)
                    ok = repo.AddEmployee(emp);
                else
                    ok = repo.UpdateEmployee(emp);

                if (!ok)
                {
                    MessageBox.Show("Thao tác không thành công (mã đã tồn tại hoặc có lỗi).", "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
                else
                {
                    MessageBox.Show("Lưu thành công!", "Thông báo", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    Close();
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error saving employee", ex);
                MessageBox.Show("Lỗi: " + ex.Message, "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
    }
}

