using HRManagement.Models;
using HRManagement.Utils;
using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Linq;

namespace HRManagement.Repository
{
    /// <summary>
    /// SQL Server implementation of IRepository.
    /// Uses ADO.NET with stored procedures for all data access.
    /// </summary>
    public class SqlRepository : IRepository
    {
        private readonly string _connectionString;

        public SqlRepository(string connectionString)
        {
            if (string.IsNullOrWhiteSpace(connectionString))
                throw new ArgumentNullException(nameof(connectionString), "Connection string cannot be null or empty");

            _connectionString = connectionString;

            // Test connection on initialization
            TestConnection();
        }

        /// <summary>
        /// Tests if the database connection is working.
        /// </summary>
        private void TestConnection()
        {
            try
            {
                using (var cn = new SqlConnection(_connectionString))
                {
                    cn.Open();
                    Logger.LogInfo("Database connection established successfully");
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Failed to connect to database", ex);
                throw new InvalidOperationException("Cannot connect to database. Check connection string.", ex);
            }
        }

        // ===================== USERS =====================

        public User ValidateUser(string username, string password)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(username) || string.IsNullOrWhiteSpace(password))
                {
                    Logger.LogSecurity($"Validation attempt with empty username/password");
                    return null;
                }

                var user = GetUserByUsername(username);
                if (user == null || !user.IsActive)
                {
                    Logger.LogSecurity($"User not found or inactive: {username}");
                    return null;
                }

                // Verify password hash
                if (!Encryption.VerifyPassword(password, user.PasswordHash))
                {
                    Logger.LogSecurity($"Invalid password for user: {username}");
                    return null;
                }

                // Update last login
                UpdateUserLastLogin(username);
                Logger.LogSecurity($"User authenticated successfully: {username}");
                return user;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error validating user: {username}", ex);
                return null;
            }
        }

        public User GetUserByUsername(string username)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(username))
                    return null;

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_GetUserByUsername", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@Username", username);

                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        if (!dr.Read())
                            return null;

                        return MapRowToUser(dr);
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error getting user: {username}", ex);
                return null;
            }
        }

        public bool AddUser(User user)
        {
            try
            {
                if (user == null || string.IsNullOrWhiteSpace(user.Username))
                {
                    Logger.LogWarn("Attempt to add null or invalid user");
                    return false;
                }

                // Check if user already exists
                if (GetUserByUsername(user.Username) != null)
                {
                    Logger.LogWarn($"User already exists: {user.Username}");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_InsertUser", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@Username", user.Username);
                    cmd.Parameters.AddWithValue("@PasswordHash", user.PasswordHash);
                    cmd.Parameters.AddWithValue("@Role", user.Role.ToString());
                    cmd.Parameters.AddWithValue("@IsActive", user.IsActive ? 1 : 0);

                    cn.Open();
                    int result = cmd.ExecuteNonQuery();

                    if (result > 0)
                    {
                        Logger.LogInfo($"User added: {user.Username}");
                        return true;
                    }
                }
            }
            catch (SqlException ex) when (ex.Number == 2627) // Unique constraint violation
            {
                Logger.LogWarn($"User already exists: {user.Username}");
                return false;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error adding user: {user.Username}", ex);
            }

            return false;
        }

        public bool UpdateUser(User user)
        {
            try
            {
                if (user == null || string.IsNullOrWhiteSpace(user.Username))
                {
                    Logger.LogWarn("Attempt to update null or invalid user");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_UpdateUser", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@Username", user.Username);
                    cmd.Parameters.AddWithValue("@PasswordHash", user.PasswordHash);
                    cmd.Parameters.AddWithValue("@Role", user.Role.ToString());
                    cmd.Parameters.AddWithValue("@IsActive", user.IsActive ? 1 : 0);

                    cn.Open();
                    int result = cmd.ExecuteNonQuery();

                    if (result > 0)
                    {
                        Logger.LogInfo($"User updated: {user.Username}");
                        return true;
                    }
                    else
                    {
                        Logger.LogWarn($"User not found for update: {user.Username}");
                        return false;
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error updating user: {user.Username}", ex);
                return false;
            }
        }

        public bool RemoveUser(string username)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(username))
                {
                    Logger.LogWarn("Attempt to delete user with null username");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_DeleteUser", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@Username", username);

                    cn.Open();
                    int result = cmd.ExecuteNonQuery();

                    if (result > 0)
                    {
                        Logger.LogInfo($"User deleted: {username}");
                        return true;
                    }
                    else
                    {
                        Logger.LogWarn($"User not found for deletion: {username}");
                        return false;
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error deleting user: {username}", ex);
                return false;
            }
        }

        public IEnumerable<User> GetAllUsers()
        {
            var users = new List<User>();
            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_GetAllUsers", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;

                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        while (dr.Read())
                        {
                            users.Add(MapRowToUser(dr));
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error getting all users", ex);
            }
            return users;
        }

        private void UpdateUserLastLogin(string username)
        {
            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_UpdateUserLastLogin", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@Username", username);

                    cn.Open();
                    cmd.ExecuteNonQuery();
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error updating last login for user: {username}", ex);
            }
        }

        // ===================== EMPLOYEES =====================

        public Employee GetEmployeeById(string id)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(id))
                    return null;

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_GetEmployeeById", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@EmployeeId", id);

                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        if (!dr.Read())
                            return null;

                        return MapRowToEmployee(dr);
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error getting employee: {id}", ex);
                return null;
            }
        }

        public bool AddEmployee(Employee employee)
        {
            try
            {
                if (employee == null || string.IsNullOrWhiteSpace(employee.EmployeeId))
                {
                    Logger.LogWarn("Attempt to add null or invalid employee");
                    return false;
                }

                // Check if employee already exists
                if (GetEmployeeById(employee.EmployeeId) != null)
                {
                    Logger.LogWarn($"Employee already exists: {employee.EmployeeId}");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_InsertEmployee", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@EmployeeId", employee.EmployeeId);
                    cmd.Parameters.AddWithValue("@FullName", employee.FullName);
                    cmd.Parameters.AddWithValue("@BirthDate", (object)employee.BirthDate ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Gender", (object)employee.Gender ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@DepartmentId", GetDepartmentIdByName(employee.Department) ?? (object)DBNull.Value);
                    cmd.Parameters.AddWithValue("@Phone", (object)employee.Phone ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Email", (object)employee.Email ?? DBNull.Value);

                    cn.Open();
                    int result = cmd.ExecuteNonQuery();

                    if (result > 0)
                    {
                        Logger.LogInfo($"Employee added: {employee.EmployeeId} - {employee.FullName}");
                        return true;
                    }
                }
            }
            catch (SqlException ex) when (ex.Number == 2627)
            {
                Logger.LogWarn($"Employee already exists: {employee.EmployeeId}");
                return false;
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error adding employee: {employee.EmployeeId}", ex);
            }

            return false;
        }

        public bool UpdateEmployee(Employee employee)
        {
            try
            {
                if (employee == null || string.IsNullOrWhiteSpace(employee.EmployeeId))
                {
                    Logger.LogWarn("Attempt to update null or invalid employee");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_UpdateEmployee", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@EmployeeId", employee.EmployeeId);
                    cmd.Parameters.AddWithValue("@FullName", employee.FullName);
                    cmd.Parameters.AddWithValue("@BirthDate", (object)employee.BirthDate ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Gender", (object)employee.Gender ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@DepartmentId", GetDepartmentIdByName(employee.Department) ?? (object)DBNull.Value);
                    cmd.Parameters.AddWithValue("@Phone", (object)employee.Phone ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Email", (object)employee.Email ?? DBNull.Value);

                    cn.Open();
                    int result = cmd.ExecuteNonQuery();

                    if (result > 0)
                    {
                        Logger.LogInfo($"Employee updated: {employee.EmployeeId}");
                        return true;
                    }
                    else
                    {
                        Logger.LogWarn($"Employee not found for update: {employee.EmployeeId}");
                        return false;
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error updating employee: {employee.EmployeeId}", ex);
                return false;
            }
        }

        public bool RemoveEmployee(string id)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(id))
                {
                    Logger.LogWarn("Attempt to delete employee with null ID");
                    return false;
                }

                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_DeleteEmployee", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@EmployeeId", id);

                    cn.Open();
                    int result = cmd.ExecuteNonQuery();

                    if (result > 0)
                    {
                        Logger.LogInfo($"Employee deleted: {id}");
                        return true;
                    }
                    else
                    {
                        Logger.LogWarn($"Employee not found for deletion: {id}");
                        return false;
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error deleting employee: {id}", ex);
                return false;
            }
        }

        public IEnumerable<Employee> SearchEmployees(string name, string gender, DateTime? dob, string id)
        {
            var employees = new List<Employee>();
            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_SearchEmployees", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;
                    cmd.Parameters.AddWithValue("@Name", (object)name ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@Gender", (object)gender ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@BirthDate", (object)dob ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@EmployeeId", (object)id ?? DBNull.Value);
                    cmd.Parameters.AddWithValue("@DepartmentId", DBNull.Value);

                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        while (dr.Read())
                        {
                            employees.Add(MapRowToEmployee(dr));
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error searching employees", ex);
            }
            return employees;
        }

        public IEnumerable<Employee> GetAllEmployees()
        {
            var employees = new List<Employee>();
            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("usp_GetAllEmployees", cn))
                {
                    cmd.CommandType = CommandType.StoredProcedure;

                    cn.Open();
                    using (var dr = cmd.ExecuteReader())
                    {
                        while (dr.Read())
                        {
                            employees.Add(MapRowToEmployee(dr));
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error getting all employees", ex);
            }
            return employees;
        }

        // ===================== HELPERS =====================

        private int? GetDepartmentIdByName(string departmentName)
        {
            if (string.IsNullOrWhiteSpace(departmentName))
                return null;

            try
            {
                using (var cn = new SqlConnection(_connectionString))
                using (var cmd = new SqlCommand("SELECT DepartmentId FROM Departments WHERE DepartmentName = @Name", cn))
                {
                    cmd.Parameters.AddWithValue("@Name", departmentName);
                    cn.Open();
                    var result = cmd.ExecuteScalar();
                    return result == null ? (int?)null : Convert.ToInt32(result);
                }
            }
            catch (Exception ex)
            {
                Logger.LogError($"Error getting department ID for: {departmentName}", ex);
                return null;
            }
        }

        private User MapRowToUser(IDataRecord dr)
        {
            return new User
            {
                Username = dr["Username"] as string,
                PasswordHash = dr["PasswordHash"] as string,
                Role = Enum.TryParse<UserRole>(dr["Role"]?.ToString() ?? "Staff", true, out var role) 
                    ? role 
                    : UserRole.Staff,
                IsActive = dr["IsActive"] is bool b ? b : (dr["IsActive"] is int i ? i == 1 : false),
                CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now,
                LastLogin = dr["LastLogin"] as DateTime?
            };
        }

        private Employee MapRowToEmployee(IDataRecord dr)
        {
            return new Employee
            {
                EmployeeId = dr["EmployeeId"] as string,
                FullName = dr["FullName"] as string,
                BirthDate = dr["BirthDate"] as DateTime?,
                Gender = dr["Gender"] as string,
                Department = dr["DepartmentName"] as string,
                Phone = dr["Phone"] as string,
                Email = dr["Email"] as string,
                CreatedAt = dr["CreatedAt"] as DateTime? ?? DateTime.Now,
                UpdatedAt = dr["UpdatedAt"] as DateTime?
            };
        }

        public void Dispose()
        {
            // SqlConnection is closed automatically when using 'using' statement
        }
    }
}

