using System;
using System.IO;
using System.Text.Json;

namespace HRManagement.Utils
{
    /// <summary>
    /// Helper class to read appsettings.json configuration.
    /// </summary>
    public static class AppConfig
    {
        private static JsonDocument _configDocument;

        static AppConfig()
        {
            LoadConfig();
        }

        private static void LoadConfig()
        {
            try
            {
                string configPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "appsettings.json");
                if (!File.Exists(configPath))
                {
                    Logger.LogWarn($"appsettings.json not found at {configPath}");
                    return;
                }

                string json = File.ReadAllText(configPath);
                _configDocument = JsonDocument.Parse(json);
            }
            catch (Exception ex)
            {
                Logger.LogError("Error loading appsettings.json", ex);
            }
        }

        /// <summary>
        /// Get connection string
        /// </summary>
        public static string GetConnectionString()
        {
            try
            {
                var connStrElement = _configDocument?.RootElement
                    .GetProperty("ConnectionStrings")
                    .GetProperty("DefaultConnection");

                return connStrElement?.GetString() ?? 
                    "Server=.;Database=HRManagement;Integrated Security=true;TrustServerCertificate=true;";
            }
            catch (Exception ex)
            {
                Logger.LogError("Error getting connection string", ex);
                // Return default connection string
                return "Server=.;Database=HRManagement;Integrated Security=true;TrustServerCertificate=true;";
            }
        }

        /// <summary>
        /// Get if using in-memory repository
        /// </summary>
        public static bool UseInMemoryRepository()
        {
            try
            {
                var appSettings = _configDocument?.RootElement.GetProperty("AppSettings");
                return appSettings?.GetProperty("UseInMemoryRepository").GetBoolean() ?? false;
            }
            catch
            {
                return false;
            }
        }

        /// <summary>
        /// Get bcrypt work factor
        /// </summary>
        public static int GetBcryptWorkFactor()
        {
            try
            {
                var security = _configDocument?.RootElement.GetProperty("Security");
                return security?.GetProperty("BcryptWorkFactor").GetInt32() ?? 12;
            }
            catch
            {
                return 12;
            }
        }
    }
}

