using System;
using System.Windows.Forms;
using HRManagement.Repository;
using HRManagement.Utils;

namespace HRManagement
{
    static class Program
    {
        [STAThread]
        static void Main()
        {
            try
            {
                Application.EnableVisualStyles();
                Application.SetCompatibleTextRenderingDefault(false);

                Logger.LogInfo("===== HRManagement Application Started =====");

                // Create repository based on configuration
                IRepository repository;
                if (AppConfig.UseInMemoryRepository())
                {
                    Logger.LogInfo("Using InMemoryRepository");
                    repository = new InMemoryRepository();
                }
                else
                {
                    Logger.LogInfo("Using SqlRepository");
                    string connStr = AppConfig.GetConnectionString();
                    repository = new SqlRepository(connStr);
                }

                // Start login form
                Application.Run(new FormLogin(repository));

                Logger.LogInfo("===== HRManagement Application Closed =====");
            }
            catch (Exception ex)
            {
                Logger.LogError("Fatal error in application startup", ex);
                MessageBox.Show(
                    "Lỗi khởi động ứng dụng: " + ex.Message,
                    "Lỗi nghiêm trọng",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Error);
            }
        }
    }
}

