using System;
using System.Drawing;
using System.Linq;
using System.Windows.Forms;
using HRManagement.Models;
using HRManagement.Repository;
using HRManagement.Utils;

namespace HRManagement
{
    public partial class FormDepartment : Form
    {
        private readonly IRepository repo;
        private DataGridView dgvDepartments;
        private TextBox txtDeptName, txtDescription;
        private Button btnAdd, btnEdit, btnDelete, btnClose;

        public FormDepartment(IRepository repository)
        {
            repo = repository ?? throw new ArgumentNullException(nameof(repository));
            Text = "Quản lý Phòng ban";
            Size = new Size(700, 500);
            StartPosition = FormStartPosition.CenterParent;
            InitializeComponents();
            LoadDepartments();
        }

        private void InitializeComponents()
        {
            // Input panel
            GroupBox gbInput = new GroupBox { Text = "Thông tin phòng ban", Location = new Point(10, 10), Size = new Size(320, 120) };

            Label lDeptName = new Label { Text = "Tên phòng ban", Location = new Point(10, 25), AutoSize = true };
            txtDeptName = new TextBox { Location = new Point(120, 22), Width = 180 };

            Label lDesc = new Label { Text = "Mô tả", Location = new Point(10, 65), AutoSize = true };
            txtDescription = new TextBox { Location = new Point(120, 62), Width = 180, Height = 40, Multiline = true };

            gbInput.Controls.AddRange(new Control[] { lDeptName, txtDeptName, lDesc, txtDescription });
            Controls.Add(gbInput);

            // Buttons
            btnAdd = new Button { Text = "Thêm", Location = new Point(10, 140), Width = 75 };
            btnEdit = new Button { Text = "Sửa", Location = new Point(90, 140), Width = 75 };
            btnDelete = new Button { Text = "Xóa", Location = new Point(170, 140), Width = 75 };
            btnClose = new Button { Text = "Đóng", Location = new Point(250, 140), Width = 75 };

            btnAdd.Click += BtnAdd_Click;
            btnEdit.Click += BtnEdit_Click;
            btnDelete.Click += BtnDelete_Click;
            btnClose.Click += (s, e) => Close();

            Controls.AddRange(new Control[] { btnAdd, btnEdit, btnDelete, btnClose });

            // DataGridView
            dgvDepartments = new DataGridView
            {
                Location = new Point(10, 180),
                Size = new Size(660, 290),
                ReadOnly = true,
                SelectionMode = DataGridViewSelectionMode.FullRowSelect,
                AutoGenerateColumns = false
            };
            dgvDepartments.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "ID", DataPropertyName = "DepartmentId", Width = 50 });
            dgvDepartments.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Tên phòng ban", DataPropertyName = "DepartmentName", Width = 250 });
            dgvDepartments.Columns.Add(new DataGridViewTextBoxColumn { HeaderText = "Mô tả", DataPropertyName = "Description", Width = 300 });
            dgvDepartments.SelectionChanged += (s, e) => LoadSelectedDepartment();

            Controls.Add(dgvDepartments);
        }

        private void LoadDepartments()
        {
            try
            {
                var depts = repo.GetAllDepartments().ToList();
                dgvDepartments.DataSource = depts;
            }
            catch (Exception ex)
            {
                Logger.LogError("Error loading departments", ex);
                MessageBox.Show("Lỗi tải dữ liệu: " + ex.Message, "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        private void LoadSelectedDepartment()
        {
            if (dgvDepartments.SelectedRows.Count == 0)
            {
                txtDeptName.Text = "";
                txtDescription.Text = "";
                return;
            }

            var dept = dgvDepartments.SelectedRows[0].DataBoundItem as Department;
            if (dept != null)
            {
                txtDeptName.Text = dept.DepartmentName;
                txtDescription.Text = dept.Description;
                txtDeptName.Enabled = false;
            }
        }

        private void BtnAdd_Click(object sender, EventArgs e)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(txtDeptName.Text))
                {
                    MessageBox.Show("Vui lòng nhập tên phòng ban", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    return;
                }

                var dept = new Department
                {
                    DepartmentName = txtDeptName.Text.Trim(),
                    Description = txtDescription.Text.Trim()
                };

                if (repo.AddDepartment(dept))
                {
                    MessageBox.Show("Phòng ban được thêm thành công!", "Thành công", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    txtDeptName.Text = "";
                    txtDescription.Text = "";
                    txtDeptName.Enabled = true;
                    LoadDepartments();
                }
                else
                {
                    MessageBox.Show("Tên phòng ban đã tồn tại hoặc có lỗi xảy ra", "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error adding department", ex);
                MessageBox.Show("Lỗi: " + ex.Message, "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        private void BtnEdit_Click(object sender, EventArgs e)
        {
            try
            {
                if (dgvDepartments.SelectedRows.Count == 0)
                {
                    MessageBox.Show("Vui lòng chọn phòng ban để sửa", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    return;
                }

                var dept = dgvDepartments.SelectedRows[0].DataBoundItem as Department;
                if (dept == null) return;

                dept.DepartmentName = txtDeptName.Text.Trim();
                dept.Description = txtDescription.Text.Trim();

                if (repo.UpdateDepartment(dept))
                {
                    MessageBox.Show("Phòng ban được cập nhật thành công!", "Thành công", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    txtDeptName.Text = "";
                    txtDescription.Text = "";
                    txtDeptName.Enabled = true;
                    LoadDepartments();
                }
                else
                {
                    MessageBox.Show("Có lỗi xảy ra", "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error updating department", ex);
                MessageBox.Show("Lỗi: " + ex.Message, "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        private void BtnDelete_Click(object sender, EventArgs e)
        {
            try
            {
                if (dgvDepartments.SelectedRows.Count == 0)
                {
                    MessageBox.Show("Vui lòng chọn phòng ban để xóa", "Cảnh báo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    return;
                }

                var dept = dgvDepartments.SelectedRows[0].DataBoundItem as Department;
                if (dept == null) return;

                if (MessageBox.Show($"Bạn có chắc chắn muốn xóa phòng ban '{dept.DepartmentName}'?", "Xác nhận", MessageBoxButtons.YesNo, MessageBoxIcon.Question) != DialogResult.Yes)
                    return;

                if (repo.DeleteDepartment(dept.DepartmentId))
                {
                    MessageBox.Show("Phòng ban được xóa thành công!", "Thành công", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    txtDeptName.Text = "";
                    txtDescription.Text = "";
                    LoadDepartments();
                }
                else
                {
                    MessageBox.Show("Không thể xóa phòng ban nếu còn nhân viên", "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
            catch (Exception ex)
            {
                Logger.LogError("Error deleting department", ex);
                MessageBox.Show("Lỗi: " + ex.Message, "Lỗi", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
    }

    // Designer stub
    partial class FormDepartment
    {
        private System.ComponentModel.IContainer components = null;

        protected override void Dispose(bool disposing)
        {
            if (disposing && (components != null))
                components.Dispose();
            base.Dispose(disposing);
        }
    }
}

